CREATE TABLE IF NOT EXISTS attack_paths (id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, source_node VARCHAR(160) NOT NULL, destination_node VARCHAR(160) NOT NULL, path VARCHAR(2000) NOT NULL, risk_score DOUBLE PRECISION NOT NULL CHECK(risk_score BETWEEN 0 AND 100), risk_level VARCHAR(20) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
